import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.internal.$Gson$Types;
import org.junit.jupiter.api.Test;

import java.lang.reflect.*;

public class GsonTypesCanonicalizeTest {

  @Test
  public void testCanonicalize_withClass_nonArray() {
    Type input = String.class;
    Type result = $Gson$Types.canonicalize(input);
    assertSame(String.class, result);
  }

  @Test
  public void testCanonicalize_withClass_array() {
    Class<?> arrayClass = String[].class;
    Type result = $Gson$Types.canonicalize(arrayClass);
    assertTrue(result instanceof GenericArrayType);
    GenericArrayType gat = (GenericArrayType) result;
    Type componentType = gat.getGenericComponentType();
    assertSame(String.class, componentType);
  }

  @Test
  public void testCanonicalize_withParameterizedType() throws Exception {
    // Create a ParameterizedType mock
    ParameterizedType pType = mock(ParameterizedType.class);
    Type ownerType = String.class;
    Type rawType = java.util.Map.class;
    Type[] typeArgs = new Type[]{Integer.class, String.class};
    when(pType.getOwnerType()).thenReturn(ownerType);
    when(pType.getRawType()).thenReturn(rawType);
    when(pType.getActualTypeArguments()).thenReturn(typeArgs);

    Type result = $Gson$Types.canonicalize(pType);
    assertNotNull(result);
    assertTrue(result instanceof ParameterizedType);

    ParameterizedType resultPType = (ParameterizedType) result;
    assertEquals(ownerType, resultPType.getOwnerType());
    assertEquals(rawType, resultPType.getRawType());
    assertArrayEquals(typeArgs, resultPType.getActualTypeArguments());
  }

  @Test
  public void testCanonicalize_withGenericArrayType() throws Exception {
    // Create a GenericArrayType mock
    GenericArrayType gArrayType = mock(GenericArrayType.class);
    Type genericComponentType = Integer.class;
    when(gArrayType.getGenericComponentType()).thenReturn(genericComponentType);

    Type result = $Gson$Types.canonicalize(gArrayType);
    assertNotNull(result);
    assertTrue(result instanceof GenericArrayType);

    GenericArrayType resultGAT = (GenericArrayType) result;
    assertEquals(genericComponentType, resultGAT.getGenericComponentType());
  }

  @Test
  public void testCanonicalize_withWildcardType() throws Exception {
    // Create a WildcardType mock
    WildcardType wType = mock(WildcardType.class);
    Type[] upperBounds = new Type[]{Number.class};
    Type[] lowerBounds = new Type[]{Integer.class};
    when(wType.getUpperBounds()).thenReturn(upperBounds);
    when(wType.getLowerBounds()).thenReturn(lowerBounds);

    Type result = $Gson$Types.canonicalize(wType);
    assertNotNull(result);
    assertTrue(result instanceof WildcardType);

    WildcardType resultWType = (WildcardType) result;
    assertArrayEquals(upperBounds, resultWType.getUpperBounds());
    assertArrayEquals(lowerBounds, resultWType.getLowerBounds());
  }

  @Test
  public void testCanonicalize_withOtherType() {
    // Use a custom Type implementation for unsupported type
    Type customType = new Type() {};
    Type result = $Gson$Types.canonicalize(customType);
    assertSame(customType, result);
  }
}
